async function supaUpload(file, apoderado, mes) {
  const ext = file.name.split(".").pop();
  const limpio = apoderado
    .normalize("NFD").replace(/[\u0300-\u036f]/g,"")
    .replace(/[^a-zA-Z0-9\s]/g,"")
    .trim().replace(/\s+/g,"_");
  const nombre = `${limpio}_${mes}_${Date.now()}.${ext}`;
  const res = await fetch(`${SUPA_URL}/storage/v1/object/comprobantes/${nombre}`, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${SUPA_KEY}`,
      "Content-Type": file.type,
      "x-upsert": "true",
    },
    body: file,
  });
  if (!res.ok) throw new Error("Error al subir");
  return `${SUPA_URL}/storage/v1/object/public/comprobantes/${nombre}`;
}

async function supaListar() {
  const res = await fetch(`${SUPA_URL}/storage/v1/object/list/comprobantes`, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${SUPA_KEY}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ prefix: "", limit: 200 }),
  });
  if (!res.ok) return [];
  const data = await res.json();
  return (data||[]).filter(f=>!f.name.startsWith('.')).map(f => ({
    name: f.name,
    url: `${SUPA_URL}/storage/v1/object/public/comprobantes/${f.name}`,
    created: f.created_at,
  }));
}
// ─── SUPABASE DATABASE (transacciones) ───────────────────────
async function dbCargar() {
  const res = await fetch(`${SUPA_URL}/rest/v1/transacciones?order=date.asc,created_at.asc`, {
    headers: {
      "Authorization": `Bearer ${SUPA_KEY}`,
      "apikey": SUPA_KEY,
    }
  });
  if (!res.ok) return [];
  return await res.json();
}

async function dbGuardar(tx) {
  const res = await fetch(`${SUPA_URL}/rest/v1/transacciones`, {
    method: "POST",
    headers: {
      "Authorization": `Bearer ${SUPA_KEY}`,
      "apikey": SUPA_KEY,
      "Content-Type": "application/json",
      "Prefer": "return=minimal",
    },
    body: JSON.stringify(tx),
  });
  return res.ok;
}

async function dbActualizarEstado(id, status) {
  const res = await fetch(`${SUPA_URL}/rest/v1/transacciones?id=eq.${id}`, {
    method: "PATCH",
    headers: {
      "Authorization": `Bearer ${SUPA_KEY}`,
      "apikey": SUPA_KEY,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ status }),
  });
  return res.ok;
}

async function dbEliminar(id) {
  const res = await fetch(`${SUPA_URL}/rest/v1/transacciones?id=eq.${id}`, {
    method: "DELETE",
    headers: {
      "Authorization": `Bearer ${SUPA_KEY}`,
      "apikey": SUPA_KEY,
    },
  });
  return res.ok;
}





