// ─── HELPERS ──────────────────────────────────────────────────
const fCLP  = (n) => new Intl.NumberFormat("es-CL",{style:"currency",currency:"CLP",maximumFractionDigits:0}).format(n);
const fDate = (d) => { const [y,m,day]=d.split("-"); return `${day}/${m}/${y}`; };
const bMonth = (d) => parseInt(d.split("-")[1])-1;
const bDay   = (d) => parseInt(d.split("-")[2]);
const daysTo = (bd) => {
  const t=new Date(), b=new Date(bd);
  const n=new Date(t.getFullYear(),b.getMonth(),b.getDate());
  if(n<t) n.setFullYear(t.getFullYear()+1);
  return Math.ceil((n-t)/(864e5));
};

