// ─── UPLOAD MODAL ──────────────────────────────────────────────
const UploadModal = ({ apoderado, mes, onClose }) => {
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const handle = async () => {
    if(!file) return;
    setLoading(true); setError("");
    try {
      const url = await supaUpload(file, apoderado, mes);
      alert(`✅ ¡Comprobante subido!\n\nURL: ${url}`);
      onClose();
    } catch(e) {
      setError("❌ Error al subir. Intenta de nuevo.");
      setLoading(false);
    }
  };
  return (
    <Modal title="📎 Adjuntar Comprobante" onClose={onClose}>
      <p style={{margin:"0 0 1rem",fontSize:"0.9rem",color:C.textMid,fontWeight:"700"}}>
        {apoderado} — Cuota {mes}
      </p>
      <div style={{border:`2px dashed ${C.border}`,borderRadius:"1rem",padding:"2rem",textAlign:"center",background:C.greenLight,marginBottom:"1rem"}}>
        <img src={IMGS.egg_white_yellow} alt="" style={{width:48,marginBottom:"0.75rem"}}/>
        <p style={{margin:"0 0 0.75rem",fontSize:"0.85rem",color:C.textMid,fontWeight:"700"}}>Arrastra o haz clic para seleccionar</p>
        <input type="file" accept=".pdf,.jpg,.jpeg,.png" onChange={e=>setFile(e.target.files[0])}
          style={{fontSize:"0.82rem",fontFamily:"'Nunito',sans-serif"}}/>
        {file && <p style={{margin:"0.5rem 0 0",fontSize:"0.8rem",color:C.green,fontWeight:"800"}}>✅ {file.name}</p>}
        <p style={{margin:"0.5rem 0 0",fontSize:"0.75rem",color:C.textLight}}>PDF, JPG, PNG · máx. 5MB</p>
      </div>
      <div style={{display:"flex",gap:"0.75rem",justifyContent:"flex-end"}}>
        <button style={btnGhost} onClick={onClose}>Cancelar</button>
        <button style={{...btnPrimary,opacity:(file&&!loading)?1:0.5}} onClick={handle} disabled={loading}>
          <Icon name="upload" size={15}/> {loading?"Subiendo...":"Subir"}
        </button>
        {error && <p style={{color:"#e8302a",fontSize:"0.8rem",fontWeight:"800",margin:"0.5rem 0 0"}}>{error}</p>}
      </div>
    </Modal>
  );
};

// ─── PAGE 4: CUOTAS ────────────────────────────────────────────
const Cuotas = ({ role, transactions }) => {
  const [apoderados, setApoderados] = useState(MOCK_APODERADOS);
  const [uploadTarget, setUploadTarget] = useState(null);
  const [busqueda, setBusqueda] = useState("");

  const totalCuotas    = apoderados.length * CUOTA_MESES.length;
  // Contar pagadas: estado local O confirmado via transacción
  const totalPagadas = apoderados.reduce((s,a) =>
    s + CUOTA_MESES.filter(mes => {
      const pagadaLocal = a.cuotas[mes]==="pagada";
      const confirmadaTx = (transactions||[]).some(t=>
        t.status==="confirmed" &&
        t.description &&
        t.description.toLowerCase().includes(a.alumno.toLowerCase()) &&
        t.description.toLowerCase().includes(mes.toLowerCase())
      );
      return pagadaLocal || confirmadaTx;
    }).length
  , 0);
  const totalPendientes = totalCuotas - totalPagadas;
  const montoRecaudado = totalPagadas   * CUOTA_VALOR;
  const montoPendiente = totalPendientes * CUOTA_VALOR;

  const toggleCuota = (id, mes) => {
    if(role !== "treasurer") return;
    setApoderados(prev => prev.map(a => a.id!==id ? a : {...a, cuotas:{...a.cuotas,[mes]:a.cuotas[mes]==="pagada"?"pendiente":"pagada"}}));
  };

  const filtrados = apoderados.filter(a =>
    a.nombre.toLowerCase().includes(busqueda.toLowerCase()) ||
    a.alumno.toLowerCase().includes(busqueda.toLowerCase())
  );

  const fCLP = n => new Intl.NumberFormat("es-CL",{style:"currency",currency:"CLP",maximumFractionDigits:0}).format(n);

  return (
    <div>
      {/* KPIs */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))",gap:"1rem",marginBottom:"1.75rem"}}>
        {[
          {label:"Recaudado",   value:fCLP(montoRecaudado), color:"#16a34a", bg:"#f0fdf4",  img:"egg_white_green"},
          {label:"Pendiente",   value:fCLP(montoPendiente), color:C.red,     bg:C.redBg,    img:"egg_white_red"},
          {label:"Cuotas OK",   value:`${totalPagadas}/${totalCuotas}`, color:C.green, bg:C.greenLight, img:"egg_green"},
          {label:"Valor Cuota", value:fCLP(CUOTA_VALOR),   color:C.purple,  bg:C.purpleBg, img:"egg_white_purple"},
        ].map((k,i)=>(
          <div key={i} style={{background:k.bg,borderRadius:"1.25rem",padding:"1rem 1.1rem",display:"flex",alignItems:"center",gap:"0.85rem",border:`2px solid ${k.color}33`,boxShadow:`0 2px 10px ${k.color}18`}}>
            <img src={IMGS[k.img]} alt="" style={{width:44,height:"auto",filter:`drop-shadow(0 2px 6px ${k.color}88)`}}/>
            <div>
              <div style={{fontSize:"0.7rem",color:k.color,fontWeight:"900",textTransform:"uppercase",letterSpacing:"0.06em"}}>{k.label}</div>
              <div style={{fontSize:"1.05rem",fontWeight:"900",color:k.color,fontFamily:"'Nunito',sans-serif"}}>{k.value}</div>
            </div>
          </div>
        ))}
      </div>

      {/* Buscador + leyenda */}
      <div style={{display:"flex",gap:"0.75rem",alignItems:"center",marginBottom:"1.25rem",flexWrap:"wrap"}}>
        <input
          style={{...inputS, flex:1, minWidth:200, paddingLeft:"0.95rem"}}
          placeholder="🔍 Buscar apoderado o alumno..."
          value={busqueda}
          onChange={e=>setBusqueda(e.target.value)}
        />
        {role==="treasurer" && (
          <div style={{fontSize:"0.78rem",color:C.textMid,fontWeight:"700",background:C.greenLight,padding:"0.5rem 1rem",borderRadius:"0.7rem",border:`1.5px solid ${C.border}`,whiteSpace:"nowrap"}}>
            🖱️ Clic en celda = cambiar estado
          </div>
        )}
      </div>

      {/* Tabla */}
      <div style={{borderRadius:"1.25rem",overflow:"hidden",border:`2px solid ${C.border}`,background:C.white,boxShadow:`0 4px 20px ${C.green}18`}}>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:"0.82rem",fontFamily:"'Nunito',sans-serif"}}>
            <thead>
              <tr style={{background:C.green}}>
                <th style={{padding:"0.85rem 1rem",textAlign:"left",color:"#fff",fontSize:"0.77rem",fontWeight:"900",textTransform:"uppercase",position:"sticky",left:0,background:C.green,zIndex:2,whiteSpace:"nowrap"}}>
                  Apoderado / Alumno
                </th>
                {CUOTA_MESES.map(m=>(
                  <th key={m} style={{padding:"0.8rem 0.5rem",textAlign:"center",color:"#fff",fontSize:"0.72rem",fontWeight:"900",textTransform:"uppercase",whiteSpace:"nowrap",minWidth:78}}>
                    {m}
                  </th>
                ))}
                <th style={{padding:"0.8rem 0.75rem",textAlign:"center",color:"#fff",fontSize:"0.77rem",fontWeight:"900",textTransform:"uppercase",whiteSpace:"nowrap"}}>
                  Total
                </th>
              </tr>
            </thead>
            <tbody>
              {filtrados.map((a,idx)=>{
                const pagadas = Object.values(a.cuotas).filter(v=>v==="pagada").length;
                const total   = CUOTA_MESES.length;
                const pct     = Math.round((pagadas/total)*100);
                const completo = pagadas === total;
                return (
                  <tr key={a.id} style={{background:idx%2===0?C.white:"#f5fcf5",borderBottom:`1px solid ${C.border}`}}>
                    <td style={{padding:"0.75rem 1rem",position:"sticky",left:0,background:idx%2===0?C.white:"#f5fcf5",zIndex:1,borderRight:`1px solid ${C.border}`}}>
                      <div style={{fontWeight:"800",color:C.text,fontSize:"0.88rem"}}>{a.nombre}</div>
                      <div style={{fontSize:"0.75rem",color:C.textLight,fontWeight:"700",display:"flex",alignItems:"center",gap:3}}>
                        <img src={IMGS.egg_green} alt="" style={{width:13}}/> {a.alumno}
                      </div>
                    </td>
                    {CUOTA_MESES.map(mes=>{
                      const pagada = a.cuotas[mes]==="pagada";
                      // Check if there's a confirmed transaction for this apoderado+mes
                      const txMatch = (transactions||[]).find(t=>
                        t.status==="confirmed" &&
                        t.description &&
                        t.description.toLowerCase().includes(a.alumno.toLowerCase()) &&
                        t.description.toLowerCase().includes(mes.toLowerCase())
                      );
                      const tieneComprobante = txMatch && txMatch.receipt_url;
                      const confirmadoPorTx = !!txMatch;
                      const estaOK = pagada || confirmadoPorTx;
                      return (
                        <td key={mes} style={{padding:"0.45rem 0.3rem",textAlign:"center"}}>
                          <div
                            onClick={()=>!confirmadoPorTx&&toggleCuota(a.id,mes)}
                            style={{display:"flex",flexDirection:"column",alignItems:"center",gap:"0.15rem",cursor:(role==="treasurer"&&!confirmadoPorTx)?"pointer":"default"}}
                            title={confirmadoPorTx?"✅ Confirmado desde Libro Contable":(role==="treasurer"?(estaOK?"Marcar pendiente":"Marcar como pagada"):undefined)}
                          >
                            <img
                              src={IMGS[tieneComprobante?"egg_green":(estaOK?"egg_white_green":"egg_white_red")]}
                              alt=""
                              style={{width:26,height:"auto",opacity:pagada?1:0.65,transition:"all .2s"}}
                            />
                            <span style={{fontSize:"0.6rem",fontWeight:"900",color:estaOK?"#16a34a":C.red,lineHeight:1}}>
                              {estaOK?"✓":"✗"}
                            </span>
                            {role==="treasurer" && pagada && (
                              <button
                                onClick={e=>{e.stopPropagation();setUploadTarget({apoderado:a.nombre,mes});}}
                                style={{fontSize:"0.58rem",background:"none",border:"none",cursor:"pointer",color:C.textLight,padding:0,lineHeight:1}}
                                title="Adjuntar comprobante"
                              >📎</button>
                            )}
                          </div>
                        </td>
                      );
                    })}
                    <td style={{padding:"0.75rem 0.6rem",textAlign:"center"}}>
                      <div style={{fontWeight:"900",color:completo?"#16a34a":pagadas>4?C.textMid:C.red,fontSize:"0.85rem"}}>{pagadas}/{total}</div>
                      <div style={{height:5,background:"#eee",borderRadius:3,margin:"0.2rem auto",overflow:"hidden",width:50}}>
                        <div style={{height:"100%",width:`${pct}%`,background:completo?"#16a34a":C.green,borderRadius:3}}/>
                      </div>
                      <div style={{fontSize:"0.68rem",color:C.textLight,fontWeight:"800"}}>{fCLP(pagadas*CUOTA_VALOR)}</div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
            <tfoot>
              <tr style={{background:C.greenLight,borderTop:`2px solid ${C.border}`}}>
                <td style={{padding:"0.85rem 1rem",fontWeight:"900",color:C.greenDark,fontSize:"0.88rem",position:"sticky",left:0,background:C.greenLight,borderRight:`1px solid ${C.border}`}}>
                  TOTALES
                </td>
                {CUOTA_MESES.map(mes=>{
                  const n = apoderados.filter(a=>a.cuotas[mes]==="pagada").length;
                  const all = n===apoderados.length;
                  return (
                    <td key={mes} style={{padding:"0.85rem 0.3rem",textAlign:"center"}}>
                      <div style={{fontWeight:"900",color:all?"#16a34a":C.textMid,fontSize:"0.8rem"}}>{n}/{apoderados.length}</div>
                      <div style={{fontSize:"0.68rem",color:C.textLight,fontWeight:"700"}}>{fCLP(n*CUOTA_VALOR)}</div>
                    </td>
                  );
                })}
                <td style={{padding:"0.85rem 0.6rem",textAlign:"center",fontWeight:"900",color:"#16a34a",fontSize:"0.95rem"}}>
                  {fCLP(montoRecaudado)}
                </td>
              </tr>
            </tfoot>
          </table>
        </div>
      </div>

      {/* Leyenda */}
      <div style={{marginTop:"1rem",display:"flex",gap:"1.5rem",alignItems:"center",flexWrap:"wrap",padding:"0.75rem 1rem",background:C.white,borderRadius:"0.85rem",border:`1.5px solid ${C.border}`}}>
        <span style={{fontSize:"0.8rem",fontWeight:"700",color:C.textMid}}>Leyenda:</span>
        <div style={{display:"flex",alignItems:"center",gap:"0.4rem"}}>
          <img src={IMGS.egg_white_green} alt="" style={{width:20}}/>
          <span style={{fontSize:"0.8rem",color:"#16a34a",fontWeight:"800"}}>Cuota pagada</span>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:"0.4rem"}}>
          <img src={IMGS.egg_white_red} alt="" style={{width:20}}/>
          <span style={{fontSize:"0.8rem",color:C.red,fontWeight:"800"}}>Cuota pendiente</span>
        </div>
        {role==="treasurer" && (
          <span style={{fontSize:"0.8rem",color:C.textMid,fontWeight:"700"}}>
            📎 = adjuntar comprobante de transferencia
          </span>
        )}
      </div>

      {uploadTarget && (
        <UploadModal
          apoderado={uploadTarget.apoderado}
          mes={uploadTarget.mes}
          onClose={()=>setUploadTarget(null)}
        />
      )}
    </div>
  );
};

// ─── MAIN APP ─────────────────────────────────────────────────
export default function App() {
  const [page, setPage] = useState("libro");
  const [transactions, setTransactions] = useState(MOCK_TRANSACTIONS);
  const [user, setUser] = useState(null);
  const [showLogin, setShowLogin] = useState(true);
  const [loginPass, setLoginPass] = useState("");
  const [loginError, setLoginError] = useState("");
  const PASS = "Nahuel2025";
  const doLogin = (asTesorera) => {
    if (asTesorera) {
      if (loginPass === PASS) { setUser(MOCK_USER); setShowLogin(false); }
      else setLoginError("Contraseña incorrecta ❌");
    } else {
      setUser({id:"guest",name:"Apoderado",role:"parent"});
      setShowLogin(false);
    }
  };

  const nav = [
    {id:"libro",        label:"Libro Contable", egg:"egg_white_green"},
    {id:"comprobantes", label:"Comprobantes",   egg:"egg_white_yellow"},
    {id:"cumpleanos",   label:"Cumpleaños",     egg:"egg_green"},
    {id:"cuotas",       label:"Cuotas",         egg:"egg_white_purple"},
  ];

  const titles = {
    libro:        {title:"Libro Contable",   sub:"Registro de ingresos y egresos del curso",   egg:"egg_white_green"},
    comprobantes: {title:"Comprobantes",      sub:"Archivos y boletas adjuntos a movimientos",  egg:"egg_white_yellow"},
    cumpleanos:   {title:"Cumpleaños",        sub:"Fechas especiales de los estudiantes",       egg:"egg_green"},
    cuotas:       {title:"Cuotas Mensuales", sub:"Abril a Diciembre · $5.000 por mes",         egg:"egg_white_purple"},
  };

  if (showLogin) return (
    <div style={{minHeight:"100vh",background:C.bg,fontFamily:"'Nunito',system-ui,sans-serif",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{background:"#fff",borderRadius:"1.5rem",padding:"2.5rem 2rem",maxWidth:380,width:"90%",boxShadow:"0 8px 40px #3cab3c22",border:"2px solid #cdeacd",textAlign:"center"}}>
        <img src={IMGS.yoshi} alt="Yoshi" style={{width:80,marginBottom:"1rem"}}/>
        <h1 style={{fontSize:"1.3rem",fontWeight:"900",color:"#2d8a2d",margin:"0 0 0.25rem"}}>Medio Mayor C</h1>
        <p style={{fontSize:"0.85rem",color:"#7aaa7a",fontWeight:"700",margin:"0 0 1.75rem"}}>Escuela de Lenguaje Nahuel 🦕</p>
        <div style={{background:"#e8f7e8",borderRadius:"1rem",padding:"1.25rem",marginBottom:"1rem",border:"1.5px solid #cdeacd"}}>
          <p style={{fontSize:"0.85rem",fontWeight:"800",color:"#2d8a2d",margin:"0 0 0.75rem"}}>🔐 Acceso Tesorera</p>
          <input type="password" placeholder="Contraseña" value={loginPass}
            onChange={e=>{setLoginPass(e.target.value);setLoginError("");}}
            onKeyDown={e=>e.key==="Enter"&&doLogin(true)}
            style={{width:"100%",padding:"0.65rem 0.85rem",borderRadius:"0.7rem",border:`2px solid ${loginError?"#e8302a":"#cdeacd"}`,fontFamily:"'Nunito',sans-serif",fontSize:"0.9rem",outline:"none",boxSizing:"border-box",marginBottom:"0.5rem"}}/>
          {loginError&&<p style={{color:"#e8302a",fontSize:"0.8rem",fontWeight:"800",margin:"0 0 0.5rem"}}>{loginError}</p>}
          <button onClick={()=>doLogin(true)}
            style={{width:"100%",padding:"0.7rem",background:"#3cab3c",color:"#fff",border:"none",borderRadius:"0.75rem",fontWeight:"900",fontSize:"0.9rem",cursor:"pointer",fontFamily:"'Nunito',sans-serif"}}>
            Entrar como Tesorera
          </button>
        </div>
        <button onClick={()=>doLogin(false)}
          style={{width:"100%",padding:"0.65rem",background:"#fff",color:"#3d6b3d",border:"2px solid #cdeacd",borderRadius:"0.75rem",fontWeight:"800",fontSize:"0.88rem",cursor:"pointer",fontFamily:"'Nunito',sans-serif"}}>
          👀 Ver como Apoderado
        </button>
      </div>
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:C.bg,fontFamily:"'Nunito',system-ui,sans-serif"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&display=swap');
        *{box-sizing:border-box;}
        ::-webkit-scrollbar{width:6px;height:6px;}
        ::-webkit-scrollbar-track{background:${C.greenLight};}
        ::-webkit-scrollbar-thumb{background:${C.greenMid};border-radius:3px;}
        tbody tr:hover td{background:${C.greenLight}!important;transition:background .1s;}
      `}</style>

      {/* Header */}
      <header style={{background:C.white,borderBottom:`2px solid ${C.border}`,padding:"0 1.5rem",position:"sticky",top:0,zIndex:100,boxShadow:`0 2px 12px ${C.green}22`}}>
        <div style={{maxWidth:1200,margin:"0 auto",display:"flex",alignItems:"center",justifyContent:"space-between",height:68,gap:"1rem",flexWrap:"wrap"}}>

          {/* Brand */}
          <div style={{display:"flex",alignItems:"center",gap:"0.65rem",flexShrink:0}}>
            <div style={{background:"transparent",borderRadius:"1rem",lineHeight:0,display:"flex",alignItems:"center"}}>
              <img src={IMGS.yoshi} alt="Yoshi" style={{width:58,height:"auto",filter:"drop-shadow(0 2px 6px rgba(60,171,60,0.35))"}}/>
            </div>
            <div>
              <div style={{fontWeight:"900",fontSize:"1.05rem",color:C.greenDark,lineHeight:1.15}}>Medio Mayor C</div>
              <div style={{fontSize:"0.68rem",color:C.textLight,fontWeight:"700",letterSpacing:"0.02em"}}>Escuela de Lenguaje Nahuel</div>
            </div>
          </div>

          {/* Nav */}
          <nav style={{display:"flex",gap:"0.25rem",background:C.greenLight,padding:"0.3rem",borderRadius:"0.9rem",border:`2px solid ${C.border}`}}>
            {nav.map(n=>(
              <button key={n.id} onClick={()=>setPage(n.id)}
                style={{display:"flex",alignItems:"center",gap:"0.4rem",padding:"0.45rem 0.95rem",borderRadius:"0.65rem",border:"none",background:page===n.id?C.green:"transparent",color:page===n.id?C.white:C.textMid,cursor:"pointer",fontSize:"0.84rem",fontWeight:"900",fontFamily:"'Nunito',sans-serif",transition:"all .15s"}}>
                {n.egg && <img src={IMGS[n.egg]} alt="" style={{width:22,height:"auto"}}/>} {n.label}
              </button>
            ))}
          </nav>

          {/* User */}
          <div style={{display:"flex",alignItems:"center",gap:"0.75rem",flexShrink:0}}>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:"0.82rem",fontWeight:"900",color:C.text}}>{user.name}</div>
              <div style={{fontSize:"0.7rem",color:user.role==="treasurer"?C.green:C.textLight,fontWeight:"800"}}>
                {user.role==="treasurer"?<span style={{display:"inline-flex",alignItems:"center",gap:3}}><img src={IMGS.egg_white_green} alt="" style={{width:16,height:"auto"}}/>Tesorera</span>:"👁 Solo lectura"}
              </div>
            </div>
            <button style={{width:36,height:36,borderRadius:"50%",background:C.greenLight,border:`2px solid ${C.border}`,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",color:C.greenDark}} title="Cerrar sesión" onClick={()=>{setUser(null);setLoginPass("");setLoginError("");setShowLogin(true);}}>
              <Icon name="logout" size={16}/>
            </button>
          </div>
        </div>
      </header>

      {/* Rainbow strip — colores Yoshi */}
      <div style={{height:5,background:`repeating-linear-gradient(90deg,${C.green} 0,${C.green} 20px,${C.yellow} 20px,${C.yellow} 40px,${C.red} 40px,${C.red} 60px,#3b82f6 60px,#3b82f6 80px,#f97316 80px,#f97316 100px)`,opacity:0.6}}/>

      {/* Main */}
      <main style={{maxWidth:1200,margin:"0 auto",padding:"1.75rem 1.5rem"}}>
        <div style={{marginBottom:"1.5rem"}}>
          <div style={{display:"flex",alignItems:"center",gap:"0.65rem"}}>
            <img src={IMGS[titles[page].egg]} alt="" style={{width:42,height:"auto",filter:"drop-shadow(0 2px 6px rgba(0,0,0,0.12))"}}/>
            <h1 style={{margin:0,fontFamily:"'Nunito',sans-serif",fontWeight:"900",fontSize:"1.75rem",color:C.greenDark}}>{titles[page].title}</h1>
          </div>
          <p style={{margin:"0.3rem 0 0",fontSize:"0.88rem",color:C.textLight,fontWeight:"700"}}>{titles[page].sub}</p>
        </div>

        {page==="libro"        && <LibroContable transactions={transactions} setTransactions={setTransactions} role={user.role}/>}
        {page==="comprobantes" && <Comprobantes transactions={transactions}/>}
        {page==="cumpleanos"   && <Cumpleanos/>}
        {page==="cuotas"       && <Cuotas role={user.role} transactions={transactions}/>}
      </main>

      {/* Footer */}
      <footer style={{textAlign:"center",padding:"1.5rem",color:C.textLight,fontSize:"0.78rem",fontWeight:"800",borderTop:`2px solid ${C.border}`,marginTop:"2rem"}}>
        🟢 Curso Medio Mayor C · Escuela de Lenguaje Nahuel · {new Date().getFullYear()}
      </footer>
    </div>
  );
}
